INSERT INTO agents (slug, name, launch_command, executable, is_builtin, is_active, supported_modes, agentfile_source)
VALUES ('loopal', 'Loopal', 'loopal', 'loopal', true, true, 'pty,acp',
  E'# === Identity ===\nAGENT loopal\nEXECUTABLE loopal\n\n# === Mode ===\nMODE pty\nMODE acp "--acp"\n\n# === Configuration ===\nCONFIG permission_mode SELECT("supervised", "auto", "bypass") = "supervised"\n\n# === Environment ===\nENV ANTHROPIC_API_KEY SECRET OPTIONAL\nENV OPENAI_API_KEY SECRET OPTIONAL\nENV GOOGLE_API_KEY SECRET OPTIONAL\n\n# === Prompt ===\nPROMPT_POSITION prepend\n\n# === Capabilities ===\nMCP ON\n\n# === Build Logic ===\narg "--permission" config.permission_mode when config.permission_mode != "supervised"\n\nif mcp.enabled {\n  mkdir sandbox.work_dir + "/.loopal"\n  file sandbox.work_dir + "/.loopal/settings.json" json({ mcp_servers: mcp.servers })\n}\n');
